1	export function nextGeneration(grid: Array<[number, number]>): Array<[number, number]> {
2	  // Helper to check if a cell exists at coordinates
3	  const cellExists = (x: number, y: number): boolean => {
4	    return grid.some(([cx, cy]) => cx === x && cy === y);
5	  };
6	
7	  // Count neighbors for each cell
8	  const countNeighbors = (x: number, y: number): number => {
9	    const neighborOffsets = [
10	      [-1, -1], [-1, 0], [-1, 1],
11	      [0, -1],           [0, 1],
12	      [1, -1],  [1, 0],  [1, 1]
13	    ];
14	    return neighborOffsets.filter(([dx, dy]) => cellExists(x + dx, y + dy)).length;
15	  };
16	
17	  // Apply rules: live cell with < 2 neighbors dies (Rule 1)
18	  return grid.filter(([x, y]) => countNeighbors(x, y) >= 2);
19	}
